class JsonWriter {
public:
    static std::string write(const JsonValue& value) {
        return std::visit([](auto&& arg) -> std::string {
            using T = std::decay_t<decltype(arg)>;
            if constexpr (std::is_same_v<T, std::nullptr_t>) {
                return "null";
            } else if constexpr (std::is_same_v<T, bool>) {
                return arg ? "true" : "false";
            } else if constexpr (std::is_same_v<T, int>) {
                return std::to_string(arg);
            } else if constexpr (std::is_same_v<T, double>) {
                return std::to_string(arg);
            } else if constexpr (std::is_same_v<T, std::string>) {
                return write_string(arg);
            } else if constexpr (std::is_same_v<T, JsonObject>) {
                return write_object(arg);
            } else if constexpr (std::is_same_v<T, JsonArray>) {
                return write_array(arg);
            } else {
                return "";
            }
        }, value.data);
    }

private:
    static std::string write_string(const std::string& s) {
        std::string result = "\"";
        for (char c : s) {
            switch (c) {
                case '"': result += "\\\""; break;
                case '\\': result += "\\\\"; break;
                case '\b': result += "\\b"; break;
                case '\f': result += "\\f"; break;
                case '\n': result += "\\n"; break;
                case '\r': result += "\\r"; break;
                case '\t': result += "\\t"; break;
                default: result += c; break;
            }
        }
        result += "\"";
        return result;
    }

    static std::string write_object(const JsonObject& obj) {
        std::string result = "{";
        bool first = true;
        for (const auto& [key, val] : obj) {
            if (!first) {
                result += ",";
            }
            first = false;
            result += write_string(key) + ":" + write(val);
        }
        result += "}";
        return result;
    }

    static std::string write_array(const JsonArray& arr) {
        std::string result = "[";
        bool first = true;
        for (const auto& val : arr) {
            if (!first) {
                result += ",";
            }
            first = false;
            result += write(val);
        }
        result += "]";
        return result;
    }
};

