std::vector<std::string> shlex_split(const std::string& command) {
    std::vector<std::string> tokens;
    std::string token;
    bool in_quote = false;
    char quote_char = '\0';
    bool escape = false;

    for (char c : command) {
        if (escape) {
            token += c;
            escape = false;
        } else if (c == '\\') {
            escape = true;
        } else if (in_quote) {
            if (c == quote_char) {
                in_quote = false;
            } else {
                token += c;
