            }
            skip_whitespace();
            expect(':');
            skip_whitespace();
            double value = parse_number();
            result[key] = value;
            skip_whitespace();

            if (peek() == '}') {
                advance();
                break;
            }
            expect(',');
        }
        return result;
    }

    void parse_object_start() {
        skip_whitespace();
        expect('{');
    }

    std::string parse_key(const std::string& key_name) {
        skip_whitespace();
        std::string key = parse_string();
        if (key != key_name) {
            throw std::invalid_argument("unexpected key");
        }
        skip_whitespace();
        expect(':');
        skip_whitespace();
        return key;
    }

    bool has_more_fields() {
        skip_whitespace();
        return peek() != '}';
    }

    void next_field() {
        expect(',');
    }

    std::string parse_string_value() {
        skip_whitespace();
        return parse_string();
    }

    int64_t parse_int_value() {
        skip_whitespace();
        return parse_integer();
    }

    void parse_object_end() {
        skip_whitespace();
        expect('}');
    }

private:
    std::string str;
    size_t pos;

    char peek() {
        if (pos >= str.size()) throw std::invalid_argument("unexpected end of input");
        return str[pos];
    }

    char advance() {
        if (pos >= str.size()) throw std::invalid_argument("unexpected end of input");
        return str[pos++];
    }

    void skip_whitespace() {
        while (pos < str.size() && (str[pos] == ' ' || str[pos] == '\t' || str[pos] == '\n' || str[pos] == '\r')) {
