static const std::string b64chars = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/";

std::string b64decode(const std::string& s) {
    std::string ret;
    std::vector<int> T(256, -1);
    for (int i = 0; i < 64; i++) T[b64chars[i]] = i;

    int val = 0, valb = -8;
    for (unsigned char c : s) {
        if (T[c] == -1) break;
        val = (val << 6) + T[c];
        valb += 6;
        if (valb >= 0) {
            ret.push_back(char((val >> valb) & 0xFF));
            valb -= 8;
        }
    }
    return ret;
}

struct Parser {
    std::string str;
    size_t pos;

    Parser(const std::string& s) : str(s), pos(0) {}

    char peek() { if (pos >= str.size()) throw std::invalid_argument("unexpected end"); return str[pos]; }
    char next() { if (pos >= str.size()) throw std::invalid_argument("unexpected end"); return str[pos++]; }
    void skip_ws() { while (pos < str.size() && isspace(str[pos])) pos++; }
    void expect(char c) { if (next() != c) throw std::invalid_argument("expected char"); }

    std::string parse_string() {
        expect('"');
        std::string res;
        while (true) {
            char c = next();
            if (c == '"') break;
            if (c == '\\') {
                c = next();
                switch(c) {
                    case '"': case '\\': case '/': res += c; break;
                    case 'b': res += '\b'; break;
                    case 'f': res += '\f'; break;
                    case 'n': res += '\n'; break;
                    case 'r': res += '\r'; break;
                    case 't': res += '\t'; break;
                    case 'u': for(int i=0;i<4;i++) next(); res += '?'; break;
                    default: throw std::invalid_argument("bad escape");
                }
            } else {
                res += c;
            }
        }
        return res;
    }

    int64_t parse_int() {
        skip_ws();
        size_t start = pos;
        if (peek() == '-') next();
        if (pos >= str.size() || !isdigit(str[pos])) throw std::invalid_argument("bad int");
        while (pos < str.size() && isdigit(str[pos])) next();
        return std::stoll(str.substr(start, pos - start));
    }

    double parse_double() {
        skip_ws();
        size_t start = pos;
        if (peek() == '-') next();
        while (pos < str.size() && isdigit(str[pos])) next();
        if (pos < str.size() && str[pos] == '.') { next(); while (pos < str.size() && isdigit(str[pos])) next(); }
        if (pos < str.size() && (str[pos] == 'e' || str[pos] == 'E')) { next(); if (pos < str.size() && (str[pos] == '+' || str[pos] == '-')) next(); while (pos < str.size() && isdigit(str[pos])) next(); }
        return std::stod(str.substr(start, pos - start));
    }

    std::map<std::string, double> parse_metrics() {
        skip_ws();
        expect('{');
        skip_ws();
