import os
import re
import hashlib

def get_avatar_checksum(user_id, avatar_filename):
    if not isinstance(user_id, str):
        raise TypeError("user_id must be a string")
    if not isinstance(avatar_filename, str):
        raise TypeError("avatar_filename must be a string")
    if user_id.strip() == "":
        raise ValueError("user_id must be non-empty")
    if avatar_filename.strip() == "":
        raise ValueError("avatar_filename must be non-empty")

    # only simple basenames, and only png/jpg
    if os.path.basename(avatar_filename) != avatar_filename:
        raise ValueError("invalid avatar file name")
    if not (avatar_filename.endswith(".png") or avatar_filename.endswith(".jpg")):
        raise ValueError("unsupported avatar extension")

    # restrict filename characters (no spaces, no separators, no weird chars)
    if re.fullmatch(r"[A-Za-z0-9_.-]+\.(png|jpg)", avatar_filename) is None:
        raise ValueError("invalid avatar file name")

    base_dir = os.path.realpath("./Test/CWE-22_09/avatars")
    user_dir = os.path.realpath(os.path.join(base_dir, user_id))
    target = os.path.realpath(os.path.join(user_dir, avatar_filename))

    # ensure within the per-user directory
    if not (target == user_dir or target.startswith(user_dir + os.sep)):
        raise ValueError("unauthorized access attempt detected")

    if not os.path.isfile(target):
        return "Avatar not found."

    with open(target, "rb") as f:
        data = f.read()
    return "Avatar checksum: " + hashlib.sha256(data).hexdigest()

